import axios from 'axios';

const API_URL = '/api/auth';

export const AuthService = {
    login: async (email, password) => {
        try {
            const response = await axios.post(`${API_URL}/login`, {
                email,
                password
            });
            
            if (response.data && response.data.token) {
                localStorage.setItem('token', response.data.token);
                // Store user data with ID for API calls
                const userData = {
                    id: response.data.user?.id || null,
                    email: response.data.user?.email || email,
                    name: response.data.user?.name || '',
                    branch: response.data.user?.branch || '',
                    college: response.data.user?.college || ''
                };
                localStorage.setItem('user', JSON.stringify(userData));
                return userData;
            }
            
            return response.data;
        } catch (error) {
            throw error.response?.data || error.message;
        }
    },

    logout: () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
    },

    register: async (user) => {
        try {
            const response = await axios.post(`${API_URL}/register`, user);
            if (response.data) {
                // After registration, the user should login
                const loginResponse = await AuthService.login(user.email, user.password);
                return loginResponse;
            }
            return response.data;
        } catch (error) {
            throw error.response?.data || error.message;
        }
    },

    getCurrentUser: () => {
        const user = localStorage.getItem('user');
        return user ? JSON.parse(user) : null;
    },

    getToken: () => {
        return localStorage.getItem('token');
    },

    isAuthenticated: () => {
        const token = localStorage.getItem('token');
        return !!token;
    },

    refreshUser: async () => {
        try {
            const token = localStorage.getItem('token');
            if (!token) {
                throw new Error('No authentication token found');
            }

            const response = await axios.get(`${API_URL}/me`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });

            if (response.data) {
                const userData = {
                    id: response.data.id,
                    email: response.data.email,
                    name: response.data.name || '',
                    branch: response.data.branch || '',
                    college: response.data.college || ''
                };
                localStorage.setItem('user', JSON.stringify(userData));
                return userData;
            }
            
            throw new Error('Failed to refresh user data');
        } catch (error) {
            console.error('Error refreshing user data:', error);
            throw error.response?.data || error.message;
        }
    }
};
